import React, { useState } from 'react';
import {
    Box,
    Button,
    Paper,
    Typography,
    Alert,
    CircularProgress,
    Card,
    CardContent,
    LinearProgress,
    List,
    ListItem,
    ListItemIcon,
    ListItemText,
} from '@mui/material';
import CloudUploadIcon from '@mui/icons-material/CloudUpload';
import CheckCircleIcon from '@mui/icons-material/CheckCircle';
import ErrorIcon from '@mui/icons-material/Error';
import { uploadDataset, trainModel, predictOnDataset, getStatistics } from '../services/api';
import { AnalysisResult, ModelMetrics, AttackStatistics } from '../types';

interface FileUploadProps {
    onAnalysisComplete?: (result: AnalysisResult, metrics: ModelMetrics, stats: AttackStatistics) => void;
}

type StepStatus = 'pending' | 'loading' | 'complete' | 'error';

interface Step {
    name: string;
    status: StepStatus;
}

const FileUpload: React.FC<FileUploadProps> = ({ onAnalysisComplete }) => {
    const [file, setFile] = useState<File | null>(null);
    const [error, setError] = useState<string | null>(null);
    const [loading, setLoading] = useState(false);
    const [success, setSuccess] = useState<string | null>(null);
    const [uploadedFilePath, setUploadedFilePath] = useState<string | null>(null);
    const [steps, setSteps] = useState<Step[]>([
        { name: 'Upload Dataset', status: 'pending' },
        { name: 'Train Model', status: 'pending' },
        { name: 'Make Predictions', status: 'pending' },
        { name: 'Get Statistics', status: 'pending' },
    ]);

    const updateStep = (index: number, status: StepStatus) => {
        const newSteps = [...steps];
        newSteps[index].status = status;
        setSteps(newSteps);
    };

    const handleFileChange = (event: React.ChangeEvent<HTMLInputElement>) => {
        const selectedFile = event.target.files?.[0];
        if (selectedFile && selectedFile.type === 'text/csv') {
            setFile(selectedFile);
            setError(null);
            setSuccess(null);
        } else {
            setError('Please upload a valid CSV file.');
            setFile(null);
        }
    };

    const handleDragOver = (e: React.DragEvent<HTMLDivElement>) => {
        e.preventDefault();
        e.currentTarget.style.backgroundColor = '#f0f0f0';
    };

    const handleDragLeave = (e: React.DragEvent<HTMLDivElement>) => {
        e.currentTarget.style.backgroundColor = 'transparent';
    };

    const handleDrop = (e: React.DragEvent<HTMLDivElement>) => {
        e.preventDefault();
        e.currentTarget.style.backgroundColor = 'transparent';
        const droppedFile = e.dataTransfer.files?.[0];
        if (droppedFile && droppedFile.type === 'text/csv') {
            setFile(droppedFile);
            setError(null);
        } else {
            setError('Please drop a valid CSV file.');
        }
    };

    const handleSubmit = async (event: React.FormEvent<HTMLFormElement>) => {
        event.preventDefault();
        if (!file) return;

        setLoading(true);
        setError(null);
        setSuccess(null);
        setSteps([
            { name: 'Upload Dataset', status: 'loading' },
            { name: 'Train Model', status: 'pending' },
            { name: 'Make Predictions', status: 'pending' },
            { name: 'Get Statistics', status: 'pending' },
        ]);

        try {
            // Step 1: Upload the dataset
            const uploadResponse = await uploadDataset(file);

            if (uploadResponse.status !== 'success') {
                throw new Error('Upload failed: ' + uploadResponse.message);
            }

            const filePath = uploadResponse.file_path;
            setUploadedFilePath(filePath);
            updateStep(0, 'complete');
            setSuccess(`Dataset uploaded successfully! (${uploadResponse.rows} rows, ${uploadResponse.columns.length} columns)`);

            // Step 2: Train the model
            updateStep(1, 'loading');
            const trainResponse = await trainModel(filePath);

            if (trainResponse.status !== 'success') {
                throw new Error('Training failed: ' + trainResponse.message);
            }

            const metrics = trainResponse.metrics;
            updateStep(1, 'complete');
            setSuccess(prev => (prev || '') + '\nModel trained successfully!');

            // Step 3: Make predictions
            updateStep(2, 'loading');
            const predictResponse = await predictOnDataset(filePath);

            if (predictResponse.status !== 'success') {
                throw new Error('Prediction failed');
            }

            updateStep(2, 'complete');

            // Step 4: Get statistics
            updateStep(3, 'loading');
            const statsResponse = await getStatistics(filePath);

            if (statsResponse.status !== 'success') {
                throw new Error('Failed to get statistics');
            }

            updateStep(3, 'complete');
            setSuccess(prev => (prev || '') + '\nAnalysis completed successfully!');

            // Call the callback if provided
            if (onAnalysisComplete) {
                onAnalysisComplete(predictResponse, metrics, statsResponse);
            }
        } catch (error) {
            const errorMessage = error instanceof Error ? error.message : 'An error occurred during analysis';
            setError(errorMessage);
            console.error('Error during analysis workflow:', error);

            // Mark current step as error
            for (let i = 0; i < steps.length; i++) {
                if (steps[i].status === 'loading') {
                    updateStep(i, 'error');
                    break;
                }
            }
        } finally {
            setLoading(false);
        }
    };

    const getStepIcon = (status: StepStatus) => {
        switch (status) {
            case 'complete':
                return <CheckCircleIcon sx={{ color: '#4caf50' }} />;
            case 'error':
                return <ErrorIcon sx={{ color: '#f44336' }} />;
            case 'loading':
                return <CircularProgress size={24} />;
            default:
                return null;
        }
    };

    return (
        <Box>
            <form onSubmit={handleSubmit}>
                {/* Drag and Drop Area */}
                <Paper
                    onDragOver={handleDragOver}
                    onDragLeave={handleDragLeave}
                    onDrop={handleDrop}
                    sx={{
                        p: 4,
                        textAlign: 'center',
                        border: '2px dashed #667eea',
                        borderRadius: 2,
                        cursor: 'pointer',
                        transition: 'all 0.3s',
                        mb: 3,
                        backgroundColor: file ? '#f5f3ff' : 'transparent',
                        '&:hover': {
                            backgroundColor: '#f5f3ff',
                            borderColor: '#764ba2',
                        },
                    }}
                >
                    <CloudUploadIcon sx={{ fontSize: 48, color: '#667eea', mb: 2 }} />
                    <Typography variant="h6" sx={{ mb: 1, fontWeight: 'bold' }}>
                        Drag and drop your CSV file here
                    </Typography>
                    <Typography variant="body2" color="text.secondary" sx={{ mb: 2 }}>
                        or click to select
                    </Typography>
                    <input
                        type="file"
                        accept=".csv"
                        onChange={handleFileChange}
                        disabled={loading}
                        style={{
                            display: 'none',
                            cursor: loading ? 'not-allowed' : 'pointer',
                        }}
                        id="file-input"
                    />
                    <label htmlFor="file-input" style={{ cursor: 'pointer' }}>
                        <Button
                            variant="contained"
                            component="span"
                            disabled={loading}
                            sx={{
                                background: 'linear-gradient(90deg, #667eea 0%, #764ba2 100%)',
                                textTransform: 'none',
                                fontSize: '1rem',
                            }}
                        >
                            Choose File
                        </Button>
                    </label>
                    {file && (
                        <Typography variant="body2" sx={{ mt: 2, color: '#4caf50', fontWeight: 'bold' }}>
                            ✓ {file.name}
                        </Typography>
                    )}
                </Paper>

                {/* Submit Button */}
                <Box sx={{ mb: 3 }}>
                    <Button
                        type="submit"
                        fullWidth
                        variant="contained"
                        size="large"
                        disabled={!file || loading}
                        sx={{
                            background: 'linear-gradient(90deg, #667eea 0%, #764ba2 100%)',
                            fontWeight: 'bold',
                            fontSize: '1rem',
                            py: 1.5,
                            textTransform: 'none',
                        }}
                    >
                        {loading ? 'Analyzing...' : 'Upload & Analyze'}
                    </Button>
                </Box>
            </form>

            {/* Steps Progress */}
            {loading && (
                <Card sx={{ mb: 3, background: 'rgba(102, 126, 234, 0.05)' }}>
                    <CardContent>
                        <Typography variant="h6" sx={{ mb: 3, fontWeight: 'bold' }}>
                            Analysis Progress
                        </Typography>
                        <List>
                            {steps.map((step, index) => (
                                <ListItem key={index}>
                                    <ListItemIcon>{getStepIcon(step.status)}</ListItemIcon>
                                    <ListItemText
                                        primary={step.name}
                                        primaryTypographyProps={{
                                            fontWeight: step.status === 'loading' ? 'bold' : 'normal',
                                        }}
                                    />
                                </ListItem>
                            ))}
                        </List>
                        <LinearProgress
                            variant="determinate"
                            value={(steps.filter(s => s.status === 'complete').length / steps.length) * 100}
                            sx={{ mt: 2, backgroundColor: '#e0e0e0', height: 8, borderRadius: 4 }}
                        />
                    </CardContent>
                </Card>
            )}

            {/* Error Alert */}
            {error && (
                <Alert
                    severity="error"
                    sx={{ mb: 3, fontWeight: 500 }}
                    onClose={() => setError(null)}
                >
                    {error}
                </Alert>
            )}

            {/* Success Alert */}
            {success && (
                <Alert
                    severity="success"
                    sx={{ mb: 3, fontWeight: 500, whiteSpace: 'pre-wrap' }}
                    onClose={() => setSuccess(null)}
                >
                    {success}
                </Alert>
            )}

            {/* Uploaded File Path */}
            {uploadedFilePath && (
                <Card sx={{ background: 'rgba(102, 126, 234, 0.05)' }}>
                    <CardContent>
                        <Typography variant="body2" color="text.secondary">
                            <strong>Uploaded File Path:</strong>
                        </Typography>
                        <Typography variant="body2" sx={{ mt: 1, wordBreak: 'break-all' }}>
                            {uploadedFilePath}
                        </Typography>
                    </CardContent>
                </Card>
            )}
        </Box>
    );
};

export default FileUpload;
